const telefono = $input.item.json.body?.telefono || $input.item.json.telefono || '';
const mensaje = $input.item.json.body?.mensaje || $input.item.json.mensaje || '';
const nombre = $input.item.json.body?.nombre || $input.item.json.nombre || 'Amigo';

// Simular sesión (en producción usar Redis)
const session = {
  telefono,
  nombre,
  estado: $input.item.json.body?.estado || 'bienvenida',
  negocio_activo: $input.item.json.body?.negocio_activo || 0,
  intencion_crecimiento: $input.item.json.body?.intencion_crecimiento || 0,
  horizonte_continuidad: $input.item.json.body?.horizonte_continuidad || 0,
  score: 0,
  mensaje_recibido: mensaje
};

return { json: session };

const session = $input.item.json;
const estado = session.estado;

// Detectar respuesta positiva
const esPositivo = (msg) => {
  if (!msg) return false;
  const x = msg.toString().toLowerCase().trim();
  return ['sí','si','yes','claro','por supuesto','obvio','seguro','dale','ok','afirmativo','correcto','exacto'].some(p => x.includes(p));
};

let respuesta = '';
let nuevoEstado = estado;
let negocio = session.negocio_activo;
let intencion = session.intencion_crecimiento;
let horizonte = session.horizonte_continuidad;

switch(estado) {
  case 'bienvenida':
    respuesta = `¡Hola ${session.nombre}! 👋 Qué bueno verte aquí.\n\nVamos a trabajar en tu web para que atraiga clientes. ¿Te cuento cómo funciona?`;
    nuevoEstado = 'educacion';
    break;

  case 'educacion':
    respuesta = `${session.nombre}, hoy si no estás en internet, es como si no existieras. 🌐\n\nEl 87% de clientes buscan en Google antes de comprar.\n\n¿Sabías esto?`;
    nuevoEstado = 'pregunta_1';
    break;

  case 'pregunta_1':
    respuesta = `Perfecto ${session.nombre}. Ahora necesito hacerte 3 preguntas rápidas 📋\n\n1️⃣ ¿Tu negocio ya está funcionando y atendiendo clientes hoy?`;
    nuevoEstado = 'respuesta_1';
    break;

  case 'respuesta_1':
    negocio = esPositivo(session.mensaje_recibido) ? 1 : 0;
    respuesta = `2️⃣ ¿Quieres usar esta web para atraer más clientes y hacer crecer tu negocio?`;
    nuevoEstado = 'respuesta_2';
    break;

  case 'respuesta_2':
    intencion = esPositivo(session.mensaje_recibido) ? 1 : 0;
    respuesta = `3️⃣ ¿Planeas mantener tu negocio activo los próximos meses?`;
    nuevoEstado = 'respuesta_3';
    break;

  case 'respuesta_3':
    horizonte = esPositivo(session.mensaje_recibido) ? 1 : 0;
    const score = negocio + intencion + horizonte;
    if (score >= 3) {
      respuesta = `¡Genial ${session.nombre}! 🎉 Tu negocio califica perfectamente.\n\nTe explico cómo funciona:`;
      nuevoEstado = 'servicio';
    } else {
      respuesta = `${session.nombre}, gracias por tu tiempo. 🙏\n\nEste servicio es para negocios activos con intención de crecer.\n\nCuando estés listo, escríbeme. ¡Éxito!`;
      nuevoEstado = 'finalizado';
    }
    break;

  case 'servicio':
    respuesta = `${session.nombre}, así funciona 📋\n\n✅ Web profesional GRATIS\n✅ SEO optimizado\n✅ Facebook Pixel incluido\n\n💡 El hosting es como alquiler digital: $29.29/mes para mantener tu web activa 24/7.\n\n🎁 La web es GRATIS. Solo pagas el hosting.\n\n¿Te interesa?`;
    nuevoEstado = 'formulario';
    break;

  case 'formulario':
    respuesta = `¡Perfecto ${session.nombre}! 📝\n\nNecesito algunos datos de tu negocio:\n\n1. Nombre del negocio\n2. Ciudad/zona\n3. Tu email\n4. Redes sociales (si tienes)\n\nEnvíame esta info cuando puedas.`;
    nuevoEstado = 'datos_negocio';
    break;

  case 'datos_negocio':
    respuesta = `Excelente. Ahora cuéntame:\n\n5. ¿Qué servicios o productos ofreces?\n6. ¿Tienes colores de marca preferidos?\n7. ¿Tienes logo?`;
    nuevoEstado = 'confirmacion';
    break;

  case 'confirmacion':
    respuesta = `🎉 ¡Listo ${session.nombre}!\n\n📅 Próximos pasos:\n1. Diseño de tu web (3-5 días)\n2. Te muestro el resultado para tu aprobación\n3. Activas el hosting ($29.29/mes)\n4. ¡Tu web estará online!\n\n¿Alguna pregunta?`;
    nuevoEstado = 'finalizado';
    break;

  default:
    respuesta = `¡Hola! Escribe "hola" para comenzar de nuevo.`;
    nuevoEstado = 'bienvenida';
}

return {
  json: {
    telefono: session.telefono,
    nombre: session.nombre,
    respuesta,
    estado_anterior: estado,
    nuevo_estado: nuevoEstado,
    negocio_activo: negocio,
    intencion_crecimiento: intencion,
    horizonte_continuidad: horizonte,
    score: negocio + intencion + horizonte
  }
};
